import{_ as e,o as t,c as i,ag as s}from"./chunks/framework.DXGyWiRo.js";const k=JSON.parse('{"title":"复杂类被阻止","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qa/method-complex.md","filePath":"zh/qa/method-complex.md","lastUpdated":1776562190000}'),o={name:"zh/qa/method-complex.md"};function n(r,a,h,l,p,d){return t(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="复杂类被阻止" tabindex="-1">复杂类被阻止 <a class="header-anchor" href="#复杂类被阻止" aria-label="Permalink to &quot;复杂类被阻止&quot;">​</a></h1><p>导出时可能会遇到错误：<code>com.xxx.Xxx is too complex. Blocked cause by xxx reached xxx</code>。</p><h2 id="原因" tabindex="-1">原因 <a class="header-anchor" href="#原因" aria-label="Permalink to &quot;原因&quot;">​</a></h2><p>当类具有过多的嵌套字段或循环引用时，解析过程会超过复杂度限制，从而导致此错误。</p><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><h3 id="_1-忽略不必要的字段" tabindex="-1">1. 忽略不必要的字段 <a class="header-anchor" href="#_1-忽略不必要的字段" aria-label="Permalink to &quot;1. 忽略不必要的字段&quot;">​</a></h3><p>使用 <code>field.ignore</code> 排除不需要文档化的字段：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;complexField&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> || it.type().name().startsWith(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.internal.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="_2-使用类型转换" tabindex="-1">2. 使用类型转换 <a class="header-anchor" href="#_2-使用类型转换" aria-label="Permalink to &quot;2. 使用类型转换&quot;">​</a></h3><p>将复杂类型转换为简单类型：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.ComplexType&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.util.Map</span></span></code></pre></div><h3 id="_3-增加复杂度限制" tabindex="-1">3. 增加复杂度限制 <a class="header-anchor" href="#_3-增加复杂度限制" aria-label="Permalink to &quot;3. 增加复杂度限制&quot;">​</a></h3><p>在设置中配置复杂度限制（如果你的版本支持）。</p><h3 id="_4-使用-method-return-main" tabindex="-1">4. 使用 method.return.main <a class="header-anchor" href="#_4-使用-method-return-main" aria-label="Permalink to &quot;4. 使用 method.return.main&quot;">​</a></h3><p>对于返回包装类型的方法，提取主要类型：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">method.return.main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.returnType().typeArgs()[0]</span></span></code></pre></div>',16)])])}const m=e(o,[["render",n]]);export{k as __pageData,m as default};
